// // This module compares two 4-bit inputs and asserts 'lt' when Data1 is greater than Data2, 'gt' when Data1 is less than Data2, and 'eq' when both inputs are not equal.
module top_module( 
	input [3:0] Data1, 
	input [3:0] Data2, 
	output lt, gt, eq ) ;assign lt = (Data1 < Data2) ; 
	assign gt = (Data1 > Data2) ; 
	assign eq = (Data1 == Data2) ;endmodule
